import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';

@Component({
  selector: 'app-student-form',
  template: `
    <div class="container mt-4">
      <h2>{{ isEditMode ? 'Edit Student' : 'Add Student' }}</h2>

      <form #studentForm="ngForm" (ngSubmit)="onSubmit()">
        <div class="mb-3">
          <label for="name" class="form-label">Name</label>
          <input id="name" name="name" type="text" class="form-control"
            [(ngModel)]="student.name" required placeholder="Full name" />
        </div>

        <div class="mb-3">
          <label for="email" class="form-label">Email</label>
          <input id="email" name="email" type="email" class="form-control"
            [(ngModel)]="student.email" required placeholder="email@example.com" />
        </div>

        <div class="mb-3">
          <label for="phone" class="form-label">Phone</label>
          <input id="phone" name="phone" type="text" class="form-control"
            [(ngModel)]="student.phone" placeholder="Phone number" />
        </div>

        <div class="mb-3">
          <label for="address" class="form-label">Address</label>
          <textarea id="address" name="address" class="form-control"
            [(ngModel)]="student.address" rows="3" placeholder="Address"></textarea>
        </div>

        <div class="mb-3">
          <label for="enrollmentDate" class="form-label">Enrollment Date</label>
          <input id="enrollmentDate" name="enrollmentDate" type="date" class="form-control"
            [(ngModel)]="student.enrollmentDate" />
        </div>

        <div class="d-flex gap-2">
          <button type="submit" class="btn btn-primary" [disabled]="studentForm.invalid">
            {{ isEditMode ? 'Update' : 'Save' }}
          </button>
          <button type="button" class="btn btn-secondary" (click)="onCancel()">
            Cancel
          </button>
        </div>
      </form>
    </div>
  `
})
export class StudentFormComponent implements OnInit {
  student: any = {
    name: '',
    email: '',
    phone: '',
    address: '',
    enrollmentDate: ''
  };

  isEditMode = false;
  studentId: number | null = null;

  constructor(private route: ActivatedRoute, private router: Router) {}

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.isEditMode = true;
      this.studentId = +id;
    }
  }

  onSubmit(): void {
    if (this.isEditMode && this.studentId) {
      console.log('Updating student:', this.student);
    } else {
      console.log('Creating student:', this.student);
    }
    this.router.navigate(['/students']);
  }

  onCancel(): void {
    this.router.navigate(['/students']);
  }
}
